# Public API (pa:*)
  @api pa.computeDesired(bindings, carriers)  @ 111-155
      -- Pure: bindings -> { [trackGuid] = trackSpec }. Pooled duplicates collapse
      -- via the seen-keys; slot order is sorted for a stable REAPER image.
